import type { Results } from '@orama/orama';
import { PRESET_DOCS, PRESET_SHOPIFY, COLOR_SCHEME_DARK, COLOR_SCHEME_LIGHT, MODE_CLOUD, MODE_LOCAL } from '../const';
export type Mode = typeof MODE_CLOUD | typeof MODE_LOCAL;
export type Preset = typeof PRESET_DOCS | typeof PRESET_SHOPIFY;
export type ColorScheme = typeof COLOR_SCHEME_DARK | typeof COLOR_SCHEME_LIGHT;
export type Document = ShopifyDocument | DocsDocument;
export interface ShopifyDocument {
    title: string;
    tags: string[];
    description: string;
    availableForSale: boolean;
    priceRange: {
        max: number;
        min: number;
    };
}
export interface DocsDocument {
    title: string;
    content: string;
    path: string;
    category: string;
    section: string;
}
export type SearchResults = Results<Document>;
export type Analytics = {
    apiKey: string;
    indexId: string;
    enable: boolean;
};
